solution:
def count_pairs_less(a, target):
    lo, hi = 0, len(a) - 1
    count = 0
    while lo < hi:
        if a[lo] + a[hi] < target:
            count += hi - lo
            lo += 1
        else:
            hi -= 1
    return count

