    # your code here
    return s

solution:
def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    a = list(s)
    lo, hi = 0, len(a) - 1
    while lo < hi:
        if a[lo] not in vowels:
            lo += 1
        elif a[hi] not in vowels:
            hi -= 1
        else:
            a[lo], a[hi] = a[hi], a[lo]
            lo += 1
            hi -= 1
    return ''.join(a)

