solution:
def partition_sign(a):
    lo, hi = 0, len(a) - 1
    while lo < hi:
        if a[lo] < 0:
            lo += 1
        elif a[hi] >= 0:
            hi -= 1
        else:
            a[lo], a[hi] = a[hi], a[lo]
            lo += 1
            hi -= 1
    return a

