    # your code here
    return 0

solution:
def remove_dupes_two(a):
    if len(a) <= 2:
        return len(a)
    w = 2
    for r in range(2, len(a)):
        if a[r] != a[w - 2]:
            a[w] = a[r]
            w += 1
    return w

